package com.example.ecommercesearch.service;

import com.example.ecommercesearch.dto.FacetBucket;
import com.example.ecommercesearch.dto.ProductSearchRequest;
import com.example.ecommercesearch.dto.ProductSearchResponse;
import com.example.ecommercesearch.model.Product;
import com.example.ecommercesearch.model.SearchQueryLog;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.admin.indices.create.CreateIndexRequest;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.support.master.AcknowledgedResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.unit.Fuzziness;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.Aggregation;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.range.ParsedRange;
import org.elasticsearch.search.aggregations.bucket.terms.ParsedStringTerms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.stereotype.Service;
import org.elasticsearch.client.core.CountRequest;
import org.elasticsearch.action.search.SearchResponse;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.time.Instant;
import java.util.*;

@Service
public class ProductSearchService {

    private static final String PRODUCTS_INDEX = "products";
    private static final String SEARCH_QUERIES_INDEX = "search_queries";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductSearchService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    @PostConstruct
    public void initializeIndices() throws IOException {
        createProductsIndexIfNotExists();
        createSearchQueriesIndexIfNotExists();
    }

    public void indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        IndexRequest request = new IndexRequest(PRODUCTS_INDEX)
                .id(product.getId())
                .source(objectMapper.writeValueAsString(product), XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Product product : products) {
            if (product.getId() == null || product.getId().isBlank()) {
                product.setId(UUID.randomUUID().toString());
            }
            bulkRequest.add(new IndexRequest(PRODUCTS_INDEX)
                    .id(product.getId())
                    .source(objectMapper.writeValueAsString(product), XContentType.JSON));
        }
        client.bulk(bulkRequest, RequestOptions.DEFAULT);
    }

    public ProductSearchResponse search(ProductSearchRequest request, String userId, String sessionId) throws IOException {
        SearchRequest searchRequest = new SearchRequest(PRODUCTS_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            MultiMatchQueryBuilder multiMatchQuery = QueryBuilders.multiMatchQuery(request.getQuery(),
                            "name^4", "description^2", "brand^2", "category", "tags", "attributes.*")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness(Fuzziness.AUTO);
            boolQuery.must(multiMatchQuery);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getBrands() != null && !request.getBrands().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", request.getBrands()));
        }

        if (request.getCategories() != null && !request.getCategories().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category.keyword", request.getCategories()));
        }

        if (request.getAvailable() != null) {
            boolQuery.filter(QueryBuilders.termQuery("available", request.getAvailable()));
        }

        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                rangeQuery.gte(request.getMinPrice());
            }
            if (request.getMaxPrice() != null) {
                rangeQuery.lte(request.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        if (request.getAttributes() != null && !request.getAttributes().isEmpty()) {
            for (Map.Entry<String, String> entry : request.getAttributes().entrySet()) {
                boolQuery.filter(QueryBuilders.termQuery("attributes." + entry.getKey() + ".keyword", entry.getValue()));
            }
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(request.getPage() * request.getSize());
        sourceBuilder.size(request.getSize());

        if (!"_score".equalsIgnoreCase(request.getSortBy())) {
            sourceBuilder.sort(request.getSortBy(), "asc".equalsIgnoreCase(request.getSortOrder()) ? SortOrder.ASC : SortOrder.DESC);
        }

        sourceBuilder.aggregation(AggregationBuilders.terms("brandFacet").field("brand.keyword").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("categoryFacet").field("category.keyword").size(20));
        sourceBuilder.aggregation(
                AggregationBuilders.range("priceFacet")
                        .field("price")
                        .addUnboundedTo("0-50", 50)
                        .addRange("50-100", 50, 100)
                        .addRange("100-200", 100, 200)
                        .addUnboundedFrom("200+", 200)
        );

        searchRequest.source(sourceBuilder);
        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = new ArrayList<>();
        for (SearchHit hit : response.getHits().getHits()) {
            products.add(objectMapper.readValue(hit.getSourceAsString(), Product.class));
        }

        Map<String, List<FacetBucket>> facets = new HashMap<>();
        ParsedStringTerms brandFacet = response.getAggregations().get("brandFacet");
        ParsedStringTerms categoryFacet = response.getAggregations().get("categoryFacet");
        ParsedRange priceFacet = response.getAggregations().get("priceFacet");

        facets.put("brand", mapTermsFacet(brandFacet));
        facets.put("category", mapTermsFacet(categoryFacet));
        facets.put("price", mapRangeFacet(priceFacet));

        logSearchQuery(request, response.getHits().getTotalHits() != null ? response.getHits().getTotalHits().value : 0L, userId, sessionId);

        return new ProductSearchResponse(
                response.getHits().getTotalHits() != null ? response.getHits().getTotalHits().value : 0L,
                request.getPage(),
                request.getSize(),
                products,
                facets
        );
    }

    public void logSearchQuery(ProductSearchRequest request, long resultCount, String userId, String sessionId) throws IOException {
        SearchQueryLog log = new SearchQueryLog();
        log.setId(UUID.randomUUID().toString());
        log.setQuery(request.getQuery());
        log.setFilters(objectMapper.convertValue(request, new TypeReference<Map<String, Object>>() {}));
        log.setPage(request.getPage());
        log.setSize(request.getSize());
        log.setResultsCount(resultCount);
        log.setUserId(userId);
        log.setSessionId(sessionId);
        log.setSearchedAt(Instant.now());

        IndexRequest indexRequest = new IndexRequest(SEARCH_QUERIES_INDEX)
                .id(log.getId())
                .source(objectMapper.writeValueAsString(log), XContentType.JSON);
        client.index(indexRequest, RequestOptions.DEFAULT);
    }

    private List<FacetBucket> mapTermsFacet(ParsedStringTerms terms) {
        List<FacetBucket> buckets = new ArrayList<>();
        for (ParsedStringTerms.ParsedBucket bucket : terms.getBuckets()) {
            buckets.add(new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()));
        }
        return buckets;
    }

    private List<FacetBucket> mapRangeFacet(ParsedRange range) {
        List<FacetBucket> buckets = new ArrayList<>();
        for (ParsedRange.ParsedBucket bucket : range.getBuckets()) {
            buckets.add(new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()));
        }
        return buckets;
    }

    private void createProductsIndexIfNotExists() throws IOException {
        boolean exists = client.indices().exists(new GetIndexRequest(PRODUCTS_INDEX), RequestOptions.DEFAULT);
        if (exists) {
            return;
        }

        org.elasticsearch.client.indices.CreateIndexRequest request =
                new org.elasticsearch.client.indices.CreateIndexRequest(PRODUCTS_INDEX);

        request.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 1));

        String mapping = "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"sku\": {\"type\": \"keyword\"},\n" +
                "    \"name\": {\n" +
                "      \"type\": \"text\",\n" +
                "      \"fields\": {\"keyword\": {\"type\": \"keyword\"}}\n" +
                "    },\n" +
                "    \"description\": {\"type\": \"text\"},\n" +
                "    \"brand\": {\n" +
                "      \"type\": \"text\",\n" +
                "      \"fields\": {\"keyword\": {\"type\": \"keyword\"}}\n" +
                "    },\n" +
                "    \"category\": {\n" +
                "      \"type\": \"text\",\n" +
                "      \"fields\": {\"keyword\": {\"type\": \"keyword\"}}\n" +
                "    },\n" +
                "    \"tags\": {\"type\": \"text\", \"fields\": {\"keyword\": {\"type\": \"keyword\"}}},\n" +
                "    \"price\": {\"type\": \"double\"},\n" +
                "    \"currency\": {\"type\": \"keyword\"},\n" +
                "    \"stock\": {\"type\": \"integer\"},\n" +
                "    \"rating\": {\"type\": \"double\"},\n" +
                "    \"available\": {\"type\": \"boolean\"},\n" +
                "    \"attributes\": {\"type\": \"object\", \"dynamic\": true}\n" +
                "  }\n" +
                "}";

        request.mapping(mapping, XContentType.JSON);
        client.indices().create(request, RequestOptions.DEFAULT);
    }

    private void createSearchQueriesIndexIfNotExists() throws IOException {
        boolean exists = client.indices().exists(new GetIndexRequest(SEARCH_QUERIES_INDEX), RequestOptions.DEFAULT);
        if (exists) {
            return;
        }

        org.elasticsearch.client.indices.CreateIndexRequest request =
                new org.elasticsearch.client.indices.CreateIndexRequest(SEARCH_QUERIES_INDEX);

        request.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 1));

        String mapping = "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"query\": {\"type\": \"text\", \"fields\": {\"keyword\": {\"type\": \"keyword\"}}},\n" +
                "    \"filters\": {\"type\": \"object\", \"dynamic\": true},\n" +
                "    \"page\": {\"type\": \"integer\"},\n" +
                "    \"size\": {\"type\": \"integer\"},\n" +
                "    \"resultsCount\": {\"type\": \"long\"},\n" +
                "    \"userId\": {\"type\": \"keyword\"},\n" +
                "    \"sessionId\": {\"type\": \"keyword\"},\n" +
                "    \"searchedAt\": {\"type\": \"date\"}\n" +
                "  }\n" +
                "}";

        request.mapping(mapping, XContentType.JSON);
        client.indices().create(request, RequestOptions.DEFAULT);
    }
}

package com.example.ecommercesearch.controller;

import com.example.ecommercesearch.dto.ProductSearchRequest;
import com.example.ecommercesearch.dto.ProductSearchResponse;
import com.example.ecommercesearch.model.Product;
import com.example.ecommercesearch.service.ProductSearchService;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductSearchService productSearchService;

    public ProductController(ProductSearchService productSearchService) {
        this.productSearchService = productSearchService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public void indexProduct(@RequestBody Product product) throws IOException {
        productSearchService.indexProduct(product);
    }

    @PostMapping("/bulk")
    @ResponseStatus(HttpStatus.CREATED)
    public void bulkIndexProducts(@RequestBody List<Product> products) throws IOException {
        productSearchService.bulkIndexProducts(products);
    }

    @PostMapping("/search")
    public ProductSearchResponse searchProducts(
            @RequestBody ProductSearchRequest request,
            @RequestHeader(value = "X-User-Id", required = false) String userId,
            @RequestHeader(value = "X-Session-Id", required = false) String sessionId) throws IOException {
        return productSearchService.search(request, userId, sessionId);
    }
}

