import java.util.Map;

@Component
public class SampleDataLoader implements CommandLineRunner {

    private final ProductSearchService productSearchService;

    public SampleDataLoader(ProductSearchService productSearchService) {
        this.productSearchService = productSearchService;
    }

    @Override
    public void run(String... args) throws Exception {
        List<Product> products = List.of(
                new Product("1", "SKU-1001", "Apple iPhone 15", "Latest smartphone with A16 chip", "Apple", "Smartphones",
                        List.of("phone", "ios", "mobile"), new BigDecimal("999.99"), "USD", 50, 4.8, true,
                        Map.of("color", "black", "storage", "128GB")),
                new Product("2", "SKU-1002", "Samsung Galaxy S24", "Flagship Android smartphone", "Samsung", "Smartphones",
                        List.of("phone", "android", "mobile"), new BigDecimal("899.99"), "USD", 40, 4.7, true,
                        Map.of("color", "blue", "storage", "256GB")),
                new Product("3", "SKU-2001", "Sony WH-1000XM5", "Noise cancelling wireless headphones", "Sony", "Audio",
                        List.of("headphones", "wireless", "noise-cancelling"), new BigDecimal("349.99"), "USD", 75, 4.9, true,
                        Map.of("color", "silver", "type", "over-ear"))
        );

        productSearchService.bulkIndexProducts(products);
    }
}

package com.example.ecommercesearch.repository;

import com.example.ecommercesearch.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.springframework.stereotype.Repository;

import java.io.IOException;

@Repository
public class ProductDocumentRepository {

    private static final String PRODUCTS_INDEX = "products";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductDocumentRepository(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public Product findById(String id) throws IOException {
        GetResponse response = client.get(new GetRequest(PRODUCTS_INDEX, id), RequestOptions.DEFAULT);
        if (!response.isExists()) {
            return null;
        }
        return objectMapper.readValue(response.getSourceAsString(), Product.class);
    }

    public void deleteById(String id) throws IOException {
        client.delete(new DeleteRequest(PRODUCTS_INDEX, id), RequestOptions.DEFAULT);
    }
}

package com.example.ecommercesearch.controller;

import com.example.ecommercesearch.model.Product;
import com.example.ecommercesearch.repository.ProductDocumentRepository;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;

@RestController
@RequestMapping("/api/products/documents")
public class ProductDocumentController {

    private final ProductDocumentRepository repository;

    public ProductDocumentController(ProductDocumentRepository repository) {
        this.repository = repository;
    }

    @GetMapping("/{id}")
    public Product getById(@PathVariable String id) throws IOException {
        return repository.findById(id);
    }

    @DeleteMapping("/{id}")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void deleteById(@PathVariable String id) throws IOException {
        repository.deleteById(id);
    }
}

